            wdt:P1222 wd:Q1534296 ;
            wdt:P3349 "75" .
  ?ceremony p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?award.
  ?awardStatement ps:P126 ?movie.
  ?movie wdt:P31 wd:Q11424.
